step.source:
const erpPurReceiveBiz = inject('biz_ErpPurReceive');

let receive = erpPurReceiveBiz.getEntity(receiveId);
if (receive == null)
    throw new NopScriptError("erp.purchase.receive-not-found")
        .param("receiveId", receiveId);

if (receive.approveStatus != 'SUBMITTED')
    throw new NopScriptError("erp.purchase.receive-not-submitted")
        .param("receiveId", receiveId);

// ORM 关联导航：receive.order → 采购订单
let purOrder = receive.order;
if (purOrder.approveStatus != 'APPROVED')
    throw new NopScriptError("erp.purchase.order-not-approved")
        .param("orderId", receive.orderId);

// ORM 关联导航：receive.lines → 入库行, receive.order.lines → 订单行
for (let line of receive.lines) {
    let orderLine = purOrder.lines.find(l => l.id == line.orderLineId);
    let unreceived = orderLine.quantity - orderLine.receivedQty;
    if (line.quantity > unreceived)
        throw new NopScriptError("erp.purchase.receive-qty-exceed")
            .param("orderLineId", line.orderLineId)
            .param("unreceived", unreceived)
            .param("received", line.quantity);
}

$scope.receive = receive;
$scope.purOrder = purOrder;

const erpInvStockMoveBiz = inject('biz_ErpInvStockMove');
let stockMoveId = erpInvStockMoveBiz.generateForPurchaseReceive(receiveId);
$scope.stockMoveId = stockMoveId;

const erpPurOrderLineBiz = inject('biz_ErpPurOrderLine');
const erpPurOrderBiz = inject('biz_ErpPurOrder');
const erpPurReceiveBiz = inject('biz_ErpPurReceive');

for (let line of receive.lines) {
    let orderLine = purOrder.lines.find(l => l.id == line.orderLineId);
    orderLine.receivedQty = orderLine.receivedQty + line.quantity;
    erpPurOrderLineBiz.update(orderLine);
}

let allReceived = purOrder.lines.every(l => l.receivedQty >= l.quantity);
purOrder.receiveStatus = allReceived ? 'RECEIVED' : 'PARTIAL';
erpPurOrderBiz.update(purOrder);

receive.approveStatus = 'APPROVED';
receive.stockMoveId = stockMoveId;
erpPurReceiveBiz.update(receive);
